// Normaliza formato Evolution API, Z-API e MazyOS webhook
const body = $input.all()[0].json;

// --- Evolution API ---
let phone = '';
let name  = '';
let text  = '';
let hasMedia = false;
let mediaUrl = '';
let msgId = '';

if (body.data?.key?.remoteJid) {
  phone    = body.data.key.remoteJid.replace('@s.whatsapp.net', '').replace('@g.us','');
  name     = body.data.pushName || '';
  text     = body.data.message?.conversation
             || body.data.message?.extendedTextMessage?.text
             || body.data.message?.imageMessage?.caption
             || body.data.message?.documentMessage?.caption
             || '';
  msgId    = body.data.key.id || '';
  hasMedia = !!(body.data.message?.imageMessage || body.data.message?.documentMessage || body.data.message?.audioMessage);
  mediaUrl = body.data.message?.imageMessage?.url || body.data.message?.documentMessage?.url || '';
}

// --- Z-API fallback ---
if (!phone && body.phone) {
  phone    = String(body.phone).replace(/[^0-9]/g, '');
  name     = body.chatName || body.senderName || '';
  text     = body.body || body.text || '';
  hasMedia = ['DocumentReceivedCallback','ImageReceivedCallback','AudioReceivedCallback'].includes(body.type);
  mediaUrl = body.document?.url || body.image?.imageUrl || '';
  msgId    = body.messageId || '';
}

// --- Formato genérico MazyOS ---
if (!phone) {
  phone = body.from || body.sender || body.number || '';
  name  = body.pushName || body.name || body.contactName || '';
  text  = body.body || body.message || body.text || JSON.stringify(body).slice(0,200);
  msgId = body.id || '';
}

// Detecta tipo de intenção
const low = text.toLowerCase();
const isContrato     = hasMedia || /contrato|financiamento|banco|cnh|documento|pdf|foto/i.test(low);
const isBancario     = /abusivo|juros|parcela|financiamento|cdi|taxa|saldo|banco|débito|empréstimo/i.test(low);
const isImovel       = /im[oó]vel|apartamento|casa|terreno|comprar|vender|escrit[uv]|financiamento/i.test(low);
const isSucessorio   = /faleceu|herança|invent[aá]rio|partilha|herdeiro|espólio|falecimento/i.test(low);

const area = isImovel ? 'imobiliario' : isSucessorio ? 'sucessorio' : 'consumidor';

return [{
  json: {
    phone, name, text, hasMedia, mediaUrl, msgId,
    isContrato, area,
    raw: body
  }
}];
